package datastore

import (
	"time"

	"github.com/stackrox/rox/generated/storage"
	"github.com/stackrox/rox/pkg/protocompat"
)

// listAlertResponse is a helper struct for scanning ListAlert query results
// from PostgreSQL columns. The db tags match the aliases generated by
// selectQueryField from the search field labels (case-insensitive).
type listAlertResponse struct {
	ID                 string     `db:"alert_id"`
	LifecycleStage     int        `db:"lifecycle_stage"`
	Time               *time.Time `db:"violation_time"`
	State              int        `db:"violation_state"`
	PolicyID           string     `db:"policy_id"`
	PolicyName         string     `db:"policy"`
	Severity           int        `db:"severity"`
	Description        string     `db:"description"`
	Categories         []string   `db:"category"`
	EnforcementAction  int        `db:"enforcement"`
	EnforcementCount   int        `db:"enforcement_count"`
	EntityType         int        `db:"entity_type"`
	ClusterID          string     `db:"cluster_id"`
	ClusterName        string     `db:"cluster"`
	Namespace          string     `db:"namespace"`
	NamespaceID        string     `db:"namespace_id"`
	DeploymentID       string     `db:"deployment_id"`
	DeploymentName     string     `db:"deployment"`
	DeploymentType     string     `db:"deployment_type"`
	DeploymentInactive bool       `db:"inactive_deployment"`
	NodeID             string     `db:"node_id"`
	NodeName           string     `db:"node"`
	ResourceName       string     `db:"resource"`
	ResourceType       int        `db:"resource_type"`
}

// toListAlert converts the database response to a storage.ListAlert protobuf.
func (r *listAlertResponse) toListAlert() *storage.ListAlert {
	listAlert := &storage.ListAlert{
		Id:             r.ID,
		LifecycleStage: storage.LifecycleStage(r.LifecycleStage),
		Time:           protocompat.ConvertTimeToTimestampOrNil(r.Time),
		State:          storage.ViolationState(r.State),
		Policy: &storage.ListAlertPolicy{
			Id:          r.PolicyID,
			Name:        r.PolicyName,
			Severity:    storage.Severity(r.Severity),
			Description: r.Description,
			Categories:  r.Categories,
		},
		EnforcementAction: storage.EnforcementAction(r.EnforcementAction),
		EnforcementCount:  int32(r.EnforcementCount),
	}

	entityType := storage.Alert_EntityType(r.EntityType)
	switch entityType {
	case storage.Alert_DEPLOYMENT:
		listAlert.CommonEntityInfo = &storage.ListAlert_CommonEntityInfo{
			ClusterName:  r.ClusterName,
			ClusterId:    r.ClusterID,
			Namespace:    r.Namespace,
			NamespaceId:  r.NamespaceID,
			ResourceType: storage.ListAlert_DEPLOYMENT,
		}
		listAlert.Entity = &storage.ListAlert_Deployment{
			Deployment: &storage.ListAlertDeployment{
				Id:             r.DeploymentID,
				Name:           r.DeploymentName,
				DeploymentType: r.DeploymentType,
				Inactive:       r.DeploymentInactive,
			},
		}
	case storage.Alert_RESOURCE:
		resType := storage.ListAlert_ResourceType(r.ResourceType)
		listAlert.CommonEntityInfo = &storage.ListAlert_CommonEntityInfo{
			ClusterName:  r.ClusterName,
			ClusterId:    r.ClusterID,
			Namespace:    r.Namespace,
			NamespaceId:  r.NamespaceID,
			ResourceType: resType,
		}
		listAlert.Entity = &storage.ListAlert_Resource{
			Resource: &storage.ListAlert_ResourceEntity{
				Name: r.ResourceName,
			},
		}
	case storage.Alert_NODE:
		listAlert.CommonEntityInfo = &storage.ListAlert_CommonEntityInfo{
			ClusterName: r.ClusterName,
			ClusterId:   r.ClusterID,
		}
		listAlert.Entity = &storage.ListAlert_Node{
			Node: &storage.ListAlert_NodeEntity{
				Name: r.NodeName,
			},
		}
	}

	return listAlert
}
